<svg viewBox="0 0 700 430" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="28" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Báo Cáo 10-Q Của Bitmine: Doanh Thu Staking vs. Lãi/Lỗ Chưa Thực Hiện</text>
  <g font-family="sans-serif">
    <rect x="20" y="50" width="660" height="115" rx="10" fill="#18181b" stroke="#34d399" stroke-width="1.5"/>
